def G_func_api(theta,L,m_backbone,m_prism,g):
    return np.array([
        [L*g*m_backbone*math.sin(theta)/theta**2 - 2*L*g*m_backbone*(1 - math.cos(theta))/theta**3 + L*g*m_prism*((1/6)*math.cos((1/6)*theta) + (1/3)*math.cos((1/3)*theta) + (1/2)*math.cos((1/2)*theta) + (2/3)*math.cos((2/3)*theta) + (5/6)*math.cos((5/6)*theta))/theta - L*g*m_prism*(math.sin((1/6)*theta) + math.sin((1/3)*theta) + math.sin((1/2)*theta) + math.sin((2/3)*theta) + math.sin((5/6)*theta))/theta**2],
        [0]
    ])


def K_func_api(theta,E_mod,I_geom,L):
    return np.array([
        [E_mod*I_geom*theta/L],
        [0]
    ])
